public class DecimalScalePrecisionDivideFunction extends DrillBaseComputeScalePrecision { public DecimalScalePrecisionDivideFunction ( int leftPrecision , int leftScale , int rightPrecision , int rightScale ) { super ( leftPrecision , leftScale , rightPrecision , rightScale ) ; } @ Override public void computeScalePrecision ( int leftPrecision , int leftScale , int rightPrecision , int rightScale ) { outputScale = leftScale + rightScale ; int leftIntegerDigits = leftPrecision - leftScale ; int maxResultIntegerDigits = leftIntegerDigits + rightScale ; outputPrecision = CoreDecimalUtility . getPrecisionRange ( outputScale + maxResultIntegerDigits ) ; outputPrecision = Math . max ( outputPrecision , Math . max ( leftPrecision , rightPrecision ) ) ; outputScale = ( outputPrecision - maxResultIntegerDigits >= 0 ) ? ( outputPrecision - maxResultIntegerDigits ) : 0 ; } }